import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.util.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.util.steps;

import org.apache.commons.math.util.MathUtils;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

public class StepDefs {

    private int n;
    private int k;
    private long result;
    private Exception exception;

    @Given("I need to calculate the binomial coefficient {string}")
    public void i_need_to_calculate_the_binomial_coefficient(String description) {
        // This is just a setup step - no action needed
    }

    @When("n is {int}")
    public void n_is(int nValue) {
        this.n = nValue;
    }

    @When("k is {int}")
    public void k_is(int kValue) {
        this.k = kValue;
    }

    @Then("the result should be {long}")
    public void the_result_should_be(long expected) {
        try {
            result = MathUtils.binomialCoefficient(n, k);
            assertEquals("Binomial coefficient result is incorrect", expected, result);
        } catch (Exception e) {
            fail("Exception should not be thrown: " + e.getMessage());
        }
    }

    @Then("the result should be the exact value {long}")
    public void the_result_should_be_the_exact_value(long expected) {
        try {
            result = MathUtils.binomialCoefficient(n, k);
            assertEquals("Binomial coefficient result is incorrect", expected, result);
        } catch (Exception e) {
            fail("Exception should not be thrown: " + e.getMessage());
        }
    }

    @Then("the calculation should throw an ArithmeticException")
    public void the_calculation_should_throw_an_arithmetic_exception() {
        exception = null;
        try {
            result = MathUtils.binomialCoefficient(n, k);
            fail("Expected ArithmeticException but calculation completed successfully");
        } catch (ArithmeticException e) {
            // Expected behavior
            exception = e;
        } catch (Exception e) {
            fail("Expected ArithmeticException but got " + e.getClass().getSimpleName() + ": " + e.getMessage());
        }
    }
}

