public static long binomialCoefficient(final int n, final int k) {
    if (n < k) {
        throw new IllegalArgumentException(
            "must have n >= k for binomial coefficient (n,k)");
    }
    if (n < 0) {
        throw new IllegalArgumentException(
            "must have n >= 0 for binomial coefficient (n,k)");
    }
    if ((n == k) || (k == 0)) {
        return 1;
    }
    if ((k == 1) || (k == n - 1)) {
        return n;
    }

    // Use symmetry to optimize: binomial(n, k) = binomial(n, n-k)
    int kPrime = Math.min(k, n - k);

    // For n > 66, we need to check for overflow
    if (n > 66) {
        // Check if result would overflow by using the largest possible value
        // For n > 66, some coefficients may exceed Long.MAX_VALUE
        // Use the formula from binomialCoefficientDouble to check
        double binomialEstimate = Math.floor(Math.exp(binomialCoefficientLog(n, kPrime)) + 0.5);
        if (binomialEstimate > Long.MAX_VALUE) {
            throw new ArithmeticException(
                "result too large to represent in a long integer");
        }
    }

    // Calculate the binomial coefficient using exact integer arithmetic
    // Use the formula: C(n,k) = n! / (k! * (n-k)!)
    // Which can be computed as: (n * (n-1) * ... * (n-k+1)) / (k * (k-1) * ... * 1)
    // To avoid overflow: (n/k) * ((n-1)/(k-1)) * ...

    // For better numerical stability, we compute as: 
    // result = 1
    // For i from 0 to k-1: result = result * (n-i) / (i+1)
    // But to maintain integer arithmetic, we do: result = (result * (n-i)) / (i+1)
    // To avoid overflow during intermediate computation, we use mulAndCheck

    long result = 1;

    if (n <= 61) {
        // For n <= 61, the naive implementation cannot overflow
        for (int i = 0; i < kPrime; i++) {
            result = mulAndCheck(result, n - i);
            result = divAndCheck(result, i + 1);
        }
    } else {
        // For n > 61 but n <= 66, we must take care not to overflow intermediate values
        // We know that (result * i) is divisible by j, but (result * i) may overflow
        // so we compute GCD to reduce fractions before multiplication
        for (int i = 0; i < kPrime; i++) {
            // Calculate gcd of (result) and (i+1), and gcd of (n-i) and (i+1)
            // to reduce fractions before multiplication
            int tmpDen = i + 1;
            int tmpNum = n - i;

            // Reduce the fraction by GCD to avoid overflow
            int gcd = gcd(tmpNum, tmpDen);
            tmpNum /= gcd;
            tmpDen /= gcd;

            // Also reduce with current result
            gcd = gcd((int)result, tmpDen);
            result /= gcd;
            tmpDen /= gcd;

            // Now multiply and divide
            result = mulAndCheck(result, tmpNum);
            result /= tmpDen;
        }

        // Final check that result fits in long
        if (result < 0) {
            throw new ArithmeticException(
                "result too large to represent in a long integer");
        }
    }

    return result;
}

