    // Use symmetry to optimize: binomial(n, k) = binomial(n, n-k)
    int kPrime = Math.min(k, n - k);

    // For n > 66, we need to check for overflow
    if (n > 66) {
        // Check if result would overflow by using the largest possible value
        // For n > 66, some coefficients may exceed Long.MAX_VALUE
        double binomialEstimate = Math.floor(Math.exp(binomialCoefficientLog(n, kPrime)) + 0.5);
        if (binomialEstimate > Long.MAX_VALUE) {
            throw new ArithmeticException(
                "result too large to represent in a long integer");
        }
    }

    // For small n, direct computation is safe
    if (n <= 30) {  // For reasonably small values
        long result = 1;
        for (int i = 0; i < kPrime; i++) {
            result = mulAndCheck(result, n - i);
            result = Math.round(result / (double)(i + 1));  // Safe division for small numbers
        }
        return result;
    }

    // For larger values, we need to be more careful to prevent overflow
    // Use the property that C(n,k) = C(n, n-k) and compute with the smaller k
    long result = 1;

    for (int i = 0; i < kPrime; i++) {
        // To avoid overflow, we can use the fact that (result * (n-i)) / (i+1) 
        // is always an integer. To implement safely, we can check for overflow

        // First, check if multiplication would overflow
        if (result > Long.MAX_VALUE / (n - i)) {
            // This means result * (n-i) would overflow
            // We need to divide first, but this would lose precision
            // Instead, we should throw an exception or use a better algorithm
            double testResult = ((double) result) * (n - i) / (i + 1);
            if (testResult > Long.MAX_VALUE) {
                throw new ArithmeticException(
                    "result too large to represent in a long integer");
            }
        }

        result = mulAndCheck(result, n - i);
        result /= (i + 1);  // This division must be exact since binomial coefficients are integers
    }

